import React from 'react';
import Logo from './Logo.js';

const Sidebar = () => {
	return (
		<div className=".Sidebar">
		  <Logo />
		  <h1 id>Greg Suehr</h1>
		  <ul>
		    <li><a>Introduction</a></li>
		    <li><a>Resume</a></li>
		 	<li><a>Pictures</a></li>
		  	<li><a>Social</a></li>
		 </ul>
		</div>
		)
}

export default Sidebar;
